Here are pytest‑style unit tests covering:

• Happy path  
• Edge cases  
• Error cases  
• Behavior with non-dict intermediate values  
• Empty key strings  
• Default value handling

```python
import pytest
from your_module import deep_get


def test_deep_get_happy_path():
    data = {"a": {"b": {"c": 123}}}
    assert deep_get(data, "a.b.c") == 123


def test_deep_get_missing_key_returns_default():
    data = {"a": {"b": {}}}
    assert deep_get(data, "a.b.c", default="missing") == "missing"


def test_deep_get_missing_key_default_none():
    data = {"a": {}}
    assert deep_get(data, "a.b") is None


def test_deep_get_non_dict_midpath_returns_default():
    data = {"a": 5}
    assert deep_get(data, "a.b", default="bad") == "bad"


def test_deep_get_key_points_to_non_dict_leaves_unchanged():
    data = {"a": {"b": 10}}
    # Asking "a.b.c" should fail at "b" because it is not a dict
    assert deep_get(data, "a.b.c", default="nope") == "nope"


def test_deep_get_empty_keys_string_returns_original_dict():
    data = {"a": 1}
    # keys.split('.') → [''], so it will try a single empty key
    assert deep_get(data, "", default="x") == "x"


def test_deep_get_empty_keys_with_empty_key_present():
    data = {"": {"x": 1}}
    assert deep_get(data, "", default="x") == data[""]


def test_deep_get_non_dict_input_returns_default():
    assert deep_get(123, "a.b", default="bad") == "bad"


def test_deep_get_key_with_dot_literal():
    # Dots are separators, so a literal dot key cannot be accessed directly
    data = {"a.b": 1}
    assert deep_get(data, "a.b") is None  # tries nested keys, not literal key


def test_deep_get_default_is_none_even_if_value_is_none():
    data = {"a": {"b": None}}
    assert deep_get(data, "a.b", default="x") is None
